        for i in 0..<n {
            if color[i] == 0 {
                color[i] = 1
                q.append(i)

                var head = 0
                while head < q.count {
                    let u = q[head]
                    head += 1

                    for v in adj[u] {
                        if color[v] == 0 {
                            color[v] = -color[u]
                            q.append(v)
                        } else if color[v] == color[u] {
                            return 0
                        }
                    }
                }
                q.removeAll()
            }
        }

        return 1
    }
}

func isBipartite(_ arr: [Int]) -> Int {
